  }
}

/**
 * Uploads a file using the Gemini Files API (Resumable Upload)
 * Note: We still use fetch here as browser support for SDK file uploads can be environment specific,
 * but we use the resulting URI with the SDK.
 */
async function uploadFileToGemini(apiKey: string, file: File): Promise<string> {
  const metaData = {
    file: {
      display_name: file.name
    }
  };

  // 1. Initiate Resumable Upload
  const startUploadRes = await fetch(
    `https://generativelanguage.googleapis.com/upload/v1beta/files?key=${apiKey}`,
    {
      method: 'POST',
      headers: {
        'X-Goog-Upload-Protocol': 'resumable',
        'X-Goog-Upload-Command': 'start',
        'X-Goog-Upload-Header-Content-Length': file.size.toString(),
        'X-Goog-Upload-Header-Content-Type': file.type,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(metaData)
    }
  );

  const uploadUrl = startUploadRes.headers.get('x-goog-upload-url');
  if (!startUploadRes.ok || !uploadUrl) {
    throw new Error(`Failed to initiate upload: ${startUploadRes.statusText}`);
  }

  // 2. Upload the actual bytes
  const uploadRes = await fetch(uploadUrl, {
    method: 'POST',
    headers: {
      'Content-Length': file.size.toString(),
      'X-Goog-Upload-Offset': '0',
      'X-Goog-Upload-Command': 'upload, finalize'
    },
    body: file
  });

  if (!uploadRes.ok) {
    throw new Error(`Failed to upload file bytes: ${uploadRes.statusText}`);
  }

  const fileInfo = await uploadRes.json();
  const fileUri = fileInfo.file.uri;

  // 3. Check if active (Wait for processing if necessary)
  let state = fileInfo.file.state;
  while (state === 'PROCESSING') {
    await new Promise(r => setTimeout(r, 1000));
    const checkRes = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/files/${fileInfo.file.name.split('/').pop()}?key=${apiKey}`
    );
    const checkData = await checkRes.json();
    state = checkData.state;
    if (state === 'FAILED') throw new Error("File processing failed on Gemini server.");
  }

  return fileUri;
}

export const streamGeminiResponse = async (
  messages: ChatMessage[],
  activeFile: AttachedFile | null,
  isDeepThink: boolean,
  onUpdate: (content: string, reasoning: string, groundingChunks?: GroundingChunk[]) => void,
  onComplete: () => void,
  onError: (error: Error) => void
) => {
  const keys = await getApiKeys();

  if (keys.length === 0) {
    const err = new Error("Unable to retrieve API keys. Please check your connection.");
    console.error(err);
    onError(err);
    return;
  }

  let success = false;
  let lastError: Error | null = null;

  // Try keys sequentially
  for (const apiKey of keys) {
    try {
      const ai = new GoogleGenAI({ apiKey: apiKey });
      let currentFileUri = activeFile?.uri;

      // Ensure file is uploaded if we have a file but no URI yet
      if (activeFile && !currentFileUri) {
         currentFileUri = await uploadFileToGemini(apiKey, activeFile.file);
      }

      // Convert messages to SDK format
      const contents = messages
        .filter(m => m.role !== 'system')
        .map(m => {
           // Basic text part
           const parts: any[] = [{ text: m.content }];
           return {
             role: m.role === 'user' ? 'user' : 'model',
             parts: parts
           };
        });

      // Attach file to the last user message
      if (currentFileUri) {
        const lastUserMsgIndex = contents.map(c => c.role).lastIndexOf('user');
        if (lastUserMsgIndex !== -1) {
          contents[lastUserMsgIndex].parts.push({
            fileData: {
              mimeType: activeFile!.mimeType,
              fileUri: currentFileUri
            }
          });
        }
      }

      // Select model: Use 'gemini-3-pro-preview' for deep thinking/complex tasks, 'gemini-3-flash-preview' for speed
      // gemini-2.5-flash series can also be used, but gemini-3 is the current recommendation for these tasks.
      const modelId = isDeepThink ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

      // Prepare config
      const config: any = {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ googleSearch: {} }],
      };

      if (isDeepThink) {
        // When using thinkingConfig, we must also set maxOutputTokens to reserve space.
        config.maxOutputTokens = 8192; 
        config.thinkingConfig = {
          includeThoughts: true, 
          thinkingBudget: 4096,
        };
      }

      const responseStream = await ai.models.generateContentStream({
        model: modelId,
        contents: contents,
        config: config
      });

      let fullContent = "";
      let fullReasoning = "";
      let finalGroundingChunks: GroundingChunk[] | undefined;

      for await (const chunk of responseStream) {
        const candidate = chunk.candidates?.[0];
        if (!candidate) continue;

        // Extract content and reasoning
        const parts = candidate.content?.parts || [];

        for (const part of parts) {
          // Check for thought property (present in preview models when thinking is enabled)
          if ((part as any).thought) {
            fullReasoning += part.text;
          } else if (part.text) {
            fullContent += part.text;
          }
        }

        // Check for grounding metadata in this chunk
        if (candidate.groundingMetadata?.groundingChunks) {
          finalGroundingChunks = candidate.groundingMetadata.groundingChunks as GroundingChunk[];
        }

        onUpdate(fullContent, fullReasoning, finalGroundingChunks);
      }

      onComplete();
      success = true;
      break; // Exit loop on success

    } catch (error: any) {
      console.warn(`Key ending in ...${apiKey.slice(-4)} failed. Error:`, error.message);
      lastError = error;
      continue;
    }
  }

  if (!success) {
    console.error("All API keys failed to return a successful response.");
    onError(lastError || new Error("Service temporarily unavailable. Please try again later."));
  }
};

