import React, { useMemo, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { User, Bot, Copy, Download, Check, Globe, X } from 'lucide-react';
import { marked } from 'marked';
import { jsPDF } from 'jspdf';

interface MessageBubbleProps {
  message: ChatMessage;
}

export const MessageBubble: React.FC<MessageBubbleProps> = ({ message }) => {
  const isUser = message.role === 'user';
  const [copied, setCopied] = React.useState(false);
  const dialogRef = useRef<HTMLDialogElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  const htmlContent = useMemo(() => {
    if (!message.content) return '';

    const renderer = new marked.Renderer();

    renderer.code = (code, language) => {
      const validLang = language || 'plaintext';
      return `<div class="code-block-container" data-language="${validLang}"><pre><code class="language-${validLang}">${code}</code></pre></div>`;
    };

    try {
      return marked.parse(message.content, { 
        renderer, 
        breaks: true, 
        gfm: true,
        headerIds: true,
        mangle: false
      }) as string;
    } catch (e) {
      console.error("Markdown parsing error:", e);
      return message.content; 
    }
  }, [message.content]);

  useEffect(() => {
    if (!contentRef.current) return;

    const containers = contentRef.current.querySelectorAll('.code-block-container');
    containers.forEach(container => {
      if (container.querySelector('.code-header')) return;

      const lang = container.getAttribute('data-language') || 'text';
      const codeElement = container.querySelector('code');
      const codeText = codeElement?.textContent || '';

      const header = document.createElement('div');
      header.className = 'code-header flex items-center justify-between px-4 py-2 bg-gray-800 rounded-t-lg border-b border-gray-700';
      header.innerHTML = `
        <span class="text-xs font-mono font-bold text-gray-400 uppercase">${lang}</span>
        <button class="copy-btn flex items-center gap-1.5 text-xs text-gray-400 hover:text-white transition-colors">
          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg>
          Copy
        </button>
      `;

      const pre = container.querySelector('pre');
      if (pre) {
        pre.className = 'm-0 p-4 bg-gray-950 overflow-x-auto rounded-b-lg text-sm font-mono';
      }

      const btn = header.querySelector('.copy-btn');
      btn?.addEventListener('click', async () => {
        try {
          await navigator.clipboard.writeText(codeText);
          btn.innerHTML = `<span class="text-green-400">Copied!</span>`;
          setTimeout(() => {
            btn.innerHTML = `<svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"/><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"/></svg> Copy`;
          }, 2000);
        } catch (err) {}
      });

      container.insertBefore(header, pre);
      container.className = 'my-4 rounded-lg border border-gray-700 bg-gray-950 shadow-md overflow-hidden';
    });

  }, [htmlContent]);

  const handleCopy = () => {
    if (!message.content) return;
    navigator.clipboard.writeText(message.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleExport = () => {
    const doc = new jsPDF();
    doc.setFontSize(16);
    doc.text("AI Assistant Response", 10, 15);
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Generated by AI Assistant`, 10, 20);
    doc.setFontSize(12);
    doc.setTextColor(0);
    const splitText = doc.splitTextToSize(message.content, 180);
    doc.text(splitText, 10, 30);
    doc.save(`ai_response.pdf`);
  };

  const hasSources = message.groundingChunks && message.groundingChunks.length > 0;
  const isThinking = !isUser && !message.isComplete && !message.content;

  return (
    <div className="w-full mb-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
      <div className="flex flex-col gap-2">
        <h3 className={`text-sm font-bold uppercase tracking-wider flex items-center gap-2 ${isUser ? 'text-primary' : 'text-emerald-400'}`}>
          {isUser ? <><User size={16} /> User</> : <><Bot size={16} /> AI Assistant</>}
        </h3>

        <div className={`relative rounded-xl p-6 shadow-sm border ${isUser ? 'bg-surface border-gray-700/50 text-gray-100' : 'bg-background border-emerald-900/30 text-gray-100'}`}>
          {isThinking ? (
             <div className="flex items-center gap-1 h-6 py-1" role="status" aria-label="AI is thinking">
              <span className="text-sm text-gray-400 mr-2 font-medium animate-pulse">Processing</span>
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
              <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-bounce"></div>
            </div>
          ) : isUser ? (
            <p className="whitespace-pre-wrap leading-relaxed text-base">{message.content}</p>
          ) : (
            <>
              <div 
                ref={contentRef}
                className="markdown-content max-w-none text-base leading-relaxed break-words"
                dangerouslySetInnerHTML={{ __html: htmlContent }} 
              />
              {!message.isComplete && <span className="inline-block w-2 h-4 ml-1 bg-emerald-400 animate-pulse align-middle" />}
            </>
          )}

          {(isUser || (message.isComplete && message.content)) && (
            <div className="flex flex-wrap items-center gap-2 mt-4 pt-4 border-t border-gray-700/30 animate-in fade-in duration-500">
              <button onClick={handleCopy} className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-gray-800 hover:bg-gray-700 text-xs text-gray-300 transition-colors border border-gray-700">
                {copied ? <Check size={12} className="text-green-400" /> : <Copy size={12} />}
                {copied ? 'Copied' : 'Copy'}
              </button>

              {!isUser && message.content && (
                <button onClick={handleExport} className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-emerald-900/30 hover:bg-emerald-900/50 text-xs text-emerald-400 transition-colors border border-emerald-900/50">
                  <Download size={12} /> Export
                </button>
              )}

              {!isUser && hasSources && (
                <>
                  <button onClick={() => dialogRef.current?.showModal()} className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-blue-900/30 hover:bg-blue-900/50 text-xs text-blue-400 transition-colors border border-blue-900/50">
                    <Globe size={12} /> Sources ({message.groundingChunks?.length})
                  </button>
                  <dialog ref={dialogRef} className="bg-surface text-gray-100 p-0 rounded-xl border border-gray-700 shadow-2xl backdrop:bg-black/80 max-w-lg w-full m-auto">
                    <div className="p-4 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
                      <h4 className="font-bold flex items-center gap-2 text-sm"><Globe size={16} className="text-blue-400"/> Search Sources</h4>
                      <button onClick={() => dialogRef.current?.close()} className="text-gray-400 hover:text-white"><X size={18} /></button>
                    </div>
                    <div className="p-4 max-h-[60vh] overflow-y-auto space-y-3">
                      {message.groundingChunks?.map((chunk, i) => chunk.web ? (
                        <div key={i} className="bg-background p-3 rounded-lg border border-gray-700 hover:border-blue-500/50 transition-colors">
                          <a href={chunk.web.uri} target="_blank" rel="noopener noreferrer" className="block">
                            <div className="text-sm font-medium text-blue-300 mb-1 hover:underline truncate">{chunk.web.title}</div>
                            <div className="text-xs text-gray-500 truncate font-mono">{chunk.web.uri}</div>
                          </a>
                        </div>
                      ) : null)}
                    </div>
                  </dialog>
                </>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, GroundingChunk, AttachedFile } from './types';
import { streamGeminiResponse } from './services/api';
import { MessageBubble } from './components/MessageBubble';
import { ChatInput, ChatInputHandle } from './components/ChatInput';
import { Sparkles, BrainCircuit, MessageSquarePlus } from 'lucide-react';

const SIMPLE_PROMPTS = [
  "Explain quantum computing in simple terms.",
  "Write a short story about a robot who loves gardening.",
  "What are the best tips for sustainable living?",
  "Analyze this code snippet for bugs.",
  "Summarize a YouTube video about productivity.",
  "Write a python script to scrape a website."
];

const App: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [alertMessage, setAlertMessage] = useState<string>('');
  const [statusMessage, setStatusMessage] = useState<string>('');
  const [selectedPrompt, setSelectedPrompt] = useState<string>('');
  const [activeFile, setActiveFile] = useState<AttachedFile | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const chatInputRef = useRef<ChatInputHandle>(null);

  useEffect(() => {
    const handleGlobalKeyDown = (e: KeyboardEvent) => {
      if (e.altKey && e.key.toLowerCase() === 'i') {
        e.preventDefault();
        chatInputRef.current?.focus();
      }
      if (e.ctrlKey && e.key.toLowerCase() === 'j') {
        e.preventDefault();
        handleNewChat();
      }
    };
    window.addEventListener('keydown', handleGlobalKeyDown);
    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
  }, [messages.length]); 

  const showAlert = (msg: string) => {
    setAlertMessage(msg);
    setTimeout(() => setAlertMessage(''), 3000);
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleNewChat = () => {
    if (messages.length > 0) {
      if (window.confirm("Start new chat? Current history will be cleared.")) {
        setMessages([]);
        setActiveFile(null);
        showAlert("Started a new chat");
        chatInputRef.current?.focus();
      }
    } else {
       chatInputRef.current?.focus();
    }
  };

  const handleSendMessage = async (content: string, file: File | null, youtubeLinks: string[], isUrlUnderstanding: boolean) => {
    setIsLoading(true);
    setStatusMessage("AI is thinking...");

    // File uploaded only for this request if provided
    const requestFile = file ? {
      file: file,
      mimeType: file.type || 'application/octet-stream',
      name: file.name
    } : null;

    const newUserMessage: ChatMessage = { role: 'user', content, isComplete: true };
    const updatedMessages = [...messages, newUserMessage];

    setMessages(prev => [...prev, newUserMessage]);
    setMessages(prev => [...prev, { role: 'assistant', content: '', isComplete: false }]);

    await streamGeminiResponse(
      updatedMessages,
      requestFile,
      youtubeLinks,
      isUrlUnderstanding,
      (content, groundingChunks) => {
        setMessages(prev => {
          const newHistory = [...prev];
          const lastMsg = newHistory[newHistory.length - 1];
          if (lastMsg.role === 'assistant') {
            lastMsg.content = content;
            if (groundingChunks) lastMsg.groundingChunks = groundingChunks;
          }
          return newHistory;
        });
      },
      () => {
        setIsLoading(false);
        setStatusMessage("Ready");
        setMessages(prev => {
          const newHistory = [...prev];
          const lastMsg = newHistory[newHistory.length - 1];
          if (lastMsg.role === 'assistant') {
            lastMsg.isComplete = true;
          }
          return newHistory;
        });
      },
      (error) => {
        setIsLoading(false);
        setStatusMessage("Error");
        setMessages(prev => {
          const newHistory = [...prev];
          const lastMsg = newHistory[newHistory.length - 1];
          if (lastMsg.role === 'assistant') {
              lastMsg.content += `\n\n**Error:** ${error.message}`;
              lastMsg.isComplete = true; 
          }
          return newHistory;
        });
      }
    );
  };

  return (
    <div className="flex flex-col h-screen bg-background text-gray-100 font-sans selection:bg-primary/30">
      {alertMessage && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 bg-gray-900/90 text-white px-6 py-2 rounded-full text-sm font-medium backdrop-blur-sm border border-gray-700 animate-in fade-in slide-in-from-top-2 z-50 shadow-xl">
          {alertMessage}
        </div>
      )}

      <header className="flex-shrink-0 h-16 border-b border-gray-700/50 bg-surface/50 backdrop-blur-md sticky top-0 z-10 flex items-center px-4 md:px-8 justify-between">
        <h1 className="font-bold text-lg tracking-tight text-white flex items-center gap-2">
          <Sparkles size={18} className="text-primary" />
          AI assistant
        </h1>
        <button onClick={handleNewChat} className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-gray-800 hover:bg-gray-700 border border-gray-700 text-xs font-medium text-gray-300 transition-colors">
          <MessageSquarePlus size={16} />
          <span className="hidden sm:inline">New Chat</span>
        </button>
      </header>

      <main className="flex-1 overflow-y-auto px-4 py-6 md:px-8 scroll-smooth">
        <div className="max-w-4xl mx-auto min-h-full flex flex-col">
          {messages.length === 0 ? (
            <div className="flex-1 flex flex-col items-center justify-center animate-in fade-in slide-in-from-bottom-4 duration-700 pb-10">
              <div className="w-16 h-16 rounded-2xl bg-surface border border-gray-700 flex items-center justify-center mb-6 shadow-xl">
                <BrainCircuit size={32} className="text-gray-400" />
              </div>
              <h2 className="text-2xl font-bold text-gray-200 mb-2">How can I help you?</h2>
              <p className="text-gray-400 mb-8 text-center max-w-md text-sm">
                I can summarize YouTube videos, analyze files, and browse the web with URL Understanding.
              </p>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 w-full max-w-2xl">
                {SIMPLE_PROMPTS.map((prompt, i) => (
                  <button key={i} onClick={() => setSelectedPrompt(prompt)} className="group flex items-center text-left p-3 rounded-lg bg-surface/30 border border-gray-700/50 hover:bg-surface hover:border-primary/40 transition-all duration-200">
                    <span className="text-sm text-gray-300 group-hover:text-white">{prompt}</span>
                  </button>
                ))}
              </div>
            </div>
          ) : (
            <div className="flex flex-col gap-2">
              {messages.map((msg, idx) => <MessageBubble key={idx} message={msg} />)}
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>
      </main>

      <div className="flex-shrink-0 bg-surface border-t border-gray-700/50">
        <ChatInput 
          ref={chatInputRef}
          onSendMessage={handleSendMessage} 
          isLoading={isLoading} 
          prefilledText={selectedPrompt}
          onClearPrefill={() => setSelectedPrompt('')}
          statusMessage={statusMessage}
        />
      </div>
    </div>
  );
};

export default App;
